external_knowledge:
Experiment IDs are unique identifiers for each experiment; 
Tags are associated with experiments to provide context or describe their purpose (e.g., 'neural networks' or 'classification');
The count of tags for an experiment gives an idea of its complexity or scope.

sql:
SELECT model_name, family
FROM model_types
ORDER BY family, model_name;

SELECT experiment_id, COUNT(tag) AS tag_count
   FROM experiment_tags
   GROUP BY experiment_id;

SELECT config_id, COUNT(DISTINCT experiment_id) as num_experiments
FROM hyperparameter_configs
GROUP BY config_id;

SELECT config_id, config_details
FROM hyperparameter_configs
WHERE experiment_id = 0;

SELECT mean_test_score
FROM evaluation_metrics
ORDER BY mean_test_score DESC;

SELECT status, COUNT(*) AS experiment_count
FROM experiment_status
GROUP BY status;

